eval_metric &lt;- function(x, remove_na = TRUE) {

  mean_val &lt;- mean(x, na.rm = remove_na)
  sd_val &lt;- sd(x, na.rm = remove_na)

  na_count &lt;- sum(is.na(x))

  result &lt;- c(mean = mean_val, sd = sd_val, missing_count = na_count)

  return(result)
}

eval_metric(trial_data$bp_drop)

Λύση

for (i in 1:ncol(trial_data)) {

  col_name &lt;- names(trial_data)[i]
  col_data &lt;- trial_data[[i]]

  print(paste("---- Εξερεύνηση Στήλης:", col_name, "----"))

  if (is.numeric(col_data)) {
    res &lt;- eval_metric(col_data)
    print(res)

  } else if (is.logical(col_data)) {
    trues &lt;- sum(col_data, na.rm = TRUE)
    print(paste("Λογική Μεταβλητή. Πλήθος TRUE:", trues))

  } else {
    print("Κατηγορία: Κείμενο - Αγνόηση")
  }
}

Συναρτησιακός προγραμματισμός

Το πακέτο purrr για συναρτησιακό προγραμματισμό
Η R είναι μια συναρτησιακή γλώσσα. Στόχος μας είναι να αποφύγουμε τα περίπλοκα:

final_data &lt;- data.frame()

for (i in seq_along(files)) {
  temp &lt;- read_csv(files[i])
  final_data &lt;- rbind(final_data, temp) 
}


final_data &lt;- files |&gt; 
  purrr::map(readr::read_csv) |&gt; 
  purrr::list_rbind()
Η λογική του Map: Αντί να γράφουμε λούπες, “χαρτογραφούμε” μια συνάρτηση πάνω σε μια λίστα δεδομένων.

Μέρος 1ο: Σύνθετο φιλτράρισμα
Συχνά πρέπει να συνδυάσουμε πολλές λογικές συνθήκες χρησιμοποιώντας το & (ΚΑΙ) και το | (Ή). Επίσης, πρέπει να αφαιρούμε τις ελλιπείς τιμές μόνο από τις στήλες που μας ενδιαφέρουν.

# Παράδειγμα: Θέλουμε σαρκοφάγα ή φυτοφάγα που έχουν καταγεγραμμένο βάρος εγκεφάλου
msleep |&gt; 
  filter(
    (vore == "carni" | vore == "herbi"), 
    !is.na(brainwt)
  ) |&gt; 
  select(name, vore, brainwt)

